# Let's parse this CSV in python and count the compliance go/no go statuses (Decision) and the deal sales statuses (Sales status).

# Read csv
# split lines
lines = data.strip().split('\\n')
# We need to parse correctly with quotes/multiline support or simple line iteration.
# Since it is standard CSV with multiline quotes, let's use io.StringIO and csv.reader
reader = csv.reader(io.StringIO(data.strip()))
headers = next(reader)

decision_counts = {}
sales_status_counts = {}
for i, row in enumerate(reader):
    if len(row) <= 21:
        continue
    # Decision is column index 10 (0-indexed)
    decision = row[10].strip()
    # Sales status is column index 21 (0-indexed)
    sales = row[21].strip()
    
    decision_counts[decision] = decision_counts.get(decision, 0) + 1
    sales_status_counts[sales] = sales_status_counts.get(sales, 0) + 1

print("DECISION COUNTS:")
for k, v in decision_counts.items():
    print(f"  {k}: {v}")

print("SALES STATUS COUNTS:")
for k, v in sales_status_counts.items():
    print(f"  {k}: {v}")

